"""
install_phase2_calendar.py
Run from C:\\vantro-mobile:    python install_phase2_calendar.py

Installs Phase 2 of the time-off flow on mobile:
  - app/(installer)/schedule-request/_layout.tsx     (modal stack layout)
  - app/(installer)/schedule-request/type.tsx        (type tile picker)
  - app/(installer)/schedule-request/calendar.tsx    (calendar with range select)
  - app/(installer)/schedule-request/confirm.tsx     (confirm + AM/PM half-day + submit)

Also patches schedule.tsx so the Request button routes to /schedule-request/type.

REQUIRES: react-native-calendars must already be installed:
   npm install --legacy-peer-deps react-native-calendars @gorhom/bottom-sheet

Idempotent. Safe to re-run.
"""
import base64, os, sys

FILES = {
    "_layout.tsx": "",
    "type.tsx": "",
    "calendar.tsx": "",
    "confirm.tsx": "",
}

REQUEST_DIR = os.path.join("app", "(installer)", "schedule-request")
SCHEDULE_TSX = os.path.join("app", "(installer)", "schedule.tsx")


def write_file(rel_path, b64_content):
    full = os.path.join(REQUEST_DIR, rel_path)
    os.makedirs(os.path.dirname(full), exist_ok=True)
    contents = base64.b64decode(b64_content).decode("utf-8")
    with open(full, "w", encoding="utf-8", newline="\n") as f:
        f.write(contents)
    print(f"  wrote: {full}  ({len(contents)} bytes)")


def patch_schedule_tsx():
    if not os.path.exists(SCHEDULE_TSX):
        print(f"  WARN: {SCHEDULE_TSX} not found, skipping patch")
        return
    with open(SCHEDULE_TSX, "r", encoding="utf-8") as f:
        src = f.read()

    if "/schedule-request/type" in src:
        print(f"  schedule.tsx already routes correctly")
        return

    old_route = "router.push('/schedule-request' as any)"
    new_route = "router.push('/schedule-request/type' as any)"
    if old_route in src:
        src = src.replace(old_route, new_route)
        with open(SCHEDULE_TSX, "w", encoding="utf-8", newline="\n") as f:
            f.write(src)
        print(f"  PATCHED: {SCHEDULE_TSX}")
    else:
        print(f"  WARN: couldn't find route in schedule.tsx")


def main():
    cwd = os.getcwd()
    if not cwd.lower().endswith("vantro-mobile"):
        print(f"WARNING: cwd is {cwd}")
        print("Run from C:\\vantro-mobile. Continue? (y/n)")
        if input().strip().lower() != "y":
            sys.exit(1)

    os.makedirs(REQUEST_DIR, exist_ok=True)

    for fn, b64 in FILES.items():
        write_file(fn, b64)

    print()
    patch_schedule_tsx()

    print()
    print("Done.")
    print()
    print("Test:  npx expo start")
    print()
    print("react-native-calendars works in Expo Go for visual testing.")
    print("For production, build dev or production on EAS.")


if __name__ == "__main__":
    main()
